class SORTracker:

    def __init__(self):
        self.max_heap = []
        self.min_heap = []
        self.count = 0

    def add(self, name: str, score: int) -> None:
        if self.max_heap and (-self.max_heap[0][0], self.max_heap[0][1]) >= (-score, name):
            heapq.heappush(self.max_heap, (-score, name))
        else:
            heapq.heappush(self.min_heap, (score, name))
        if len(self.max_heap) > self.count + 1:
            score, name = heapq.heappop(self.max_heap)
            heapq.heappush(self.min_heap, (-score, name))
        elif len(self.max_heap) < self.count + 1 and self.min_heap:
            score, name = heapq.heappop(self.min_heap)
            heapq.heappush(self.max_heap, (-score, name))

    def get(self) -> str:
        self.count += 1
        if len(self.max_heap) < self.count:
            score, name = heapq.heappop(self.min_heap)
            heapq.heappush(self.max_heap, (-score, name))
        return self.max_heap[0][1]


